const PROCESSING_FEE = 5;
const COMPONENT_PREMIUM = 25;
const BUILDING_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: COMPONENT_PREMIUM,
};

function calculateItemPremiums(items: any[]): number {
  const counts: Record<string, number> = {};
  let total = 0;

  for (const item of items) {
    const base = BASE_PREMIUMS[item.type];
    if (base === COMPONENT_PREMIUM) {
      counts[item.type] = (counts[item.type] || 0) + 1;
    } else {
      total += base;
    }
  }

  for (const type in counts) {
    const count = counts[type];
    const blocks = Math.floor(count / 3);
    const remainder = count % 3;
    total += blocks * BUILDING_BLOCK_PREMIUM + remainder * COMPONENT_PREMIUM;
  }

  return total;
}

export function processScenario(scenario: any): any {
  const results = scenario.steps.map((step: any) => {
    const totalBasePremium = calculateItemPremiums(step.items);
    const premium = Math.round(totalBasePremium * 1.1) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

